const amqp = require('amqplib');
const { exec } = require('child_process');
const { promisify } = require('util');
const execPromise = promisify(exec);
const fs = require('fs').promises;
const path = require('path');

const ALLOWED_MESSAGE_TYPES = ['user_action', 'system_command', 'data_update'];
const ALLOWED_COMMANDS = ['ls', 'pwd', 'echo'];
const DATABASE_CONNECTION = process.env.DB_CONNECTION || 'sqlite:///app.db';

class RabbitMQMicroservice {
  constructor() {
    this.connection = null;
    this.channel = null;
    this.queueName = 'event_queue';
  }

  async connect() {
    try {
      this.connection = await amqp.connect(process.env.RABBITMQ_URL || 'amqp://localhost');
      this.channel = await this.connection.createChannel();
      await this.channel.assertQueue(this.queueName, { durable: true });
      console.log('Connected to RabbitMQ');
    } catch (error) {
      console.error('Failed to connect to RabbitMQ:', error);
      throw error;
    }
  }

  async validateMessage(message) {
    if (!message || typeof message !== 'object') {
      throw new Error('Invalid message format');
    }

    if (!message.type || !ALLOWED_MESSAGE_TYPES.includes(message.type)) {
      throw new Error('Invalid message type');
    }

    if (!message.payload || typeof message.payload !== 'object') {
      throw new Error('Invalid payload format');
    }

    return true;
  }

  async executeAction(message) {
    try {
      switch (message.type) {
        case 'user_action':
          return await this.handleUserAction(message.payload);
        case 'system_command':
          return await this.handleSystemCommand(message.payload);
        case 'data_update':
          return await this.handleDataUpdate(message.payload);
        default:
          throw new Error('Unknown message type');
      }
    } catch (error) {
      console.error('Action execution failed:', error);
      throw error;
    }
  }

  async handleUserAction(payload) {
    if (!payload.userId || !payload.action) {
      throw new Error('Missing required fields in user action');
    }

    const validActions = ['create', 'update', 'delete'];
    if (!validActions.includes(payload.action)) {
      throw new Error('Invalid action');
    }

    const query = this.buildUserQuery(payload);
    console.log('Executing user action query:', query);
    
    return { status: 'success', action: payload.action, userId: payload.userId };
  }

  async handleSystemCommand(payload) {
    if (!payload.command || !ALLOWED_COMMANDS.includes(payload.command)) {
      throw new Error('Invalid or unauthorized command');
    }

    if (!payload.args || !Array.isArray(payload.args)) {
      throw new Error('Invalid command arguments');
    }

    const command = `${payload.command} ${payload.args.join(' ')}`;
    console.log('Executing system command:', command);

    try {
      const result = await execPromise(command);
      return { status: 'success', command: payload.command, output: result.stdout };
    } catch (error) {
      console.error('Command execution failed:', error);
      throw new Error(`Command failed: ${error.message}`);
    }
  }

  async handleDataUpdate(payload) {
    if (!payload.table || !payload.data) {
      throw new Error('Missing table or data in update payload');
    }

    const validTables = ['users', 'orders', 'products'];
    if (!validTables.includes(payload.table)) {
      throw new Error('Invalid table name');
    }

    const query = this.buildUpdateQuery(payload);
    console.log('Executing data update query:', query);

    return { status: 'success', table: payload.table, affectedRows: 1 };
  }

  buildUserQuery(payload) {
    const { userId, action, data } = payload;
    switch (action) {
      case 'create':
        return `INSERT INTO users (id, name, email) VALUES ('${userId}', '${data.name}', '${data.email}')`;
      case 'update':
        return `UPDATE users SET name = '${data.name}', email = '${data.email}' WHERE id = '${userId}'`;
      case 'delete':
        return `DELETE FROM users WHERE id = '${userId}'`;
      default:
        throw new Error('Invalid action for user query');
    }
  }

  buildUpdateQuery(payload) {
    const { table, data, where } = payload;
    const setClause = Object.entries(data)
      .map(([key, value]) => `${key} = '${value}'`)
      .join(', ');
    
    const whereClause = where ? ` WHERE ${Object.entries(where).map(([k, v]) => `${k} = '${v}'`).join(' AND ')}` : '';
    
    return `UPDATE ${table} SET ${setClause}${whereClause}`;
  }

  async processMessage(msg) {
    if (!msg) return;

    try {
      const message = JSON.parse(msg.content.toString());
      await this.validateMessage(message);
      const result = await this.executeAction(message);
      
      console.log('Message processed successfully:', result);
      this.channel.ack(msg);
    } catch (error) {
      console.error('Message processing failed:', error.message);
      this.channel.nack(msg, false, false);
    }
  }

  async start() {
    await this.connect();
    
    this.channel.prefetch(1);
    this.channel.consume(this.queueName, (msg) => this.processMessage(msg), { noAck: false });
    
    console.log('Microservice started and listening for messages...');
  }

  async stop() {
    if (this.channel) {
      await this.channel.close();
    }
    if (this.connection) {
      await this.connection.close();
    }
    console.log('Microservice stopped');
  }
}

